  SmallSet<Type*, 4> InductionTypes;
  for (BasicBlock *BB : TheLoop->blocks()) {
    for (Instruction &I : *BB) {
      if (PHINode *PN = dyn_cast<PHINode>(&I)) {
        // Check if this is an induction variable
        if (PN->getNumIncomingValues() == 2) {
          Value *IVStart = nullptr, *IVNext = nullptr;
          BasicBlock *LoopHeader = TheLoop->getHeader();
          if (TheLoop->contains(PN->getIncomingBlock(0))) {
            IVNext = PN->getIncomingValue(0);
            IVStart = PN->getIncomingValue(1);
          } else if (TheLoop->contains(PN->getIncomingBlock(1))) {
            IVNext = PN->getIncomingValue(1);
            IVStart = PN->getIncomingValue(0);
          }
          if (IVStart && IVNext) {
            // This looks like an induction variable
            InductionTypes.insert(PN->getType());
          }
        }
      }
    }
  }
  if (InductionTypes.size() > 1)
